import * as React from 'react';
import {useRef} from 'react';

import PlayCircleIcon from '@mui/icons-material/PlayCircle';

const SimpleVideo = ({src,style}) => {
  const styles = {
    "video-box": { position: "relative" },
    "video-box video": { display: "inline-block", verticalAlign: "baseline" },
    "video-img": {
      position: "absolute",
      top: "0",
      bottom: "0",
      width: "100%",
      zIndex: 999,
      backgroundSize: "100% 100%",
      cursor: "pointer",
      display: "flex",
      justifyContent: "center",
      alignItems: "center"
    },
    "video-player-icon": { fontSize: "10rem !important" }
  }
  const myRef = useRef(null);
  const [state, setState] = React.useState(false);

  const playVideo = (event) => {
    myRef.current.play();
    setState(true);
  };
  return (<div style={styles['video-box']}>
      <video  onPause={() => setState(false)} onEnded={() => setState(false)}
             style={{width:'100%',...style}}
             src={src} ref={myRef}
      >
      </video>
      {!state &&
          <div style={styles['video-img']}>
            <PlayCircleIcon onClick={playVideo}
                                                           style={{fontSize:'8rem'}}
                                                           fontSize={'large'}/>
          </div>}
    </div>);
};

export default SimpleVideo;
